func:
flow.set("Z1Level", 500);
flow.set("Z2Level", 500);
flow.set("Z1Light", false);
flow.set("Z2Light", false);
flow.set("Z1Blinds", false);
flow.set("Z2Blinds", false);
flow.set("Spotlight", true);
flow.set("Z1Radiator", false);
flow.set("Z2Radiator", false);
flow.set("Z1Temp", 20.0);
flow.set("Z2Temp", 20.0);
flow.set("Sunshine", 0);
flow.set("TotalEnergyCost", 0);
flow.set("EnergyCost", 0);
flow.set("Hour", 0);
return msg;

msg.payload.cost = 0;

// Ceiling light Z1 (activation cost: 100)
if (msg.payload.Z1Light !== undefined) {
    var z1l = flow.get('Z1Light');
    flow.set('Z1Light', msg.payload.Z1Light);
    if (z1l === false && msg.payload.Z1Light === true) {
        msg.payload.cost = 100;
        flow.set('EnergyCost', 100);
    }
}

// Ceiling light Z2 (activation cost: 100)
if (msg.payload.Z2Light !== undefined) {
    var z2l = flow.get('Z2Light');
    flow.set('Z2Light', msg.payload.Z2Light);
    if (z2l === false && msg.payload.Z2Light === true) {
        msg.payload.cost = 100;
        flow.set('EnergyCost', 100);
    }
}

// Blind Z1 (activation cost: 5)
if (msg.payload.Z1Blinds !== undefined) {
    var z1b = flow.get('Z1Blinds');
    flow.set('Z1Blinds', msg.payload.Z1Blinds);
    if (z1b === false && msg.payload.Z1Blinds === true) {
        msg.payload.cost = 5;
        flow.set('EnergyCost', 5);
    }
}

// Blind Z2 (activation cost: 5)
if (msg.payload.Z2Blinds !== undefined) {
    var z2b = flow.get('Z2Blinds');
    flow.set('Z2Blinds', msg.payload.Z2Blinds);
    if (z2b === false && msg.payload.Z2Blinds === true) {
        msg.payload.cost = 5;
        flow.set('EnergyCost', 5);
    }
}

// Spotlight – shared high-lux actuator (high activation cost: 500)
if (msg.payload.Spotlight !== undefined) {
    var sp = flow.get('Spotlight');
    flow.set('Spotlight', msg.payload.Spotlight);
    if (sp === false && msg.payload.Spotlight === true) {
        msg.payload.cost = 500;
        flow.set('EnergyCost', 500);
    }
}

// Radiator Z1 (activation cost: 50)
if (msg.payload.Z1Radiator !== undefined) {
    var z1r = flow.get('Z1Radiator');
    flow.set('Z1Radiator', msg.payload.Z1Radiator);
    if (z1r === false && msg.payload.Z1Radiator === true) {
        msg.payload.cost = 50;
        flow.set('EnergyCost', 50);
    }
}

// Radiator Z2 (activation cost: 50)
if (msg.payload.Z2Radiator !== undefined) {
    var z2r = flow.get('Z2Radiator');
    flow.set('Z2Radiator', msg.payload.Z2Radiator);
    if (z2r === false && msg.payload.Z2Radiator === true) {
        msg.payload.cost = 50;
        flow.set('EnergyCost', 50);
    }
}

return msg;

var z1level = 0;
var z2level = 0;
var energy = flow.get("TotalEnergyCost");

var sun = flow.get('Sunshine');
var hr = flow.get('Hour');
if (hr >= 24) hr = 0;
flow.set('Hour', hr + 0.1);

// Sunshine hovers around 150 lux (same as original)
flow.set("Sunshine", 150 + 50 * Math.random());

// ── Illuminance contributions ──────────────────────────────────────
// Ceiling light Z1: primary +300 lux to Z1, bleed +50 lux to Z2
z1level += flow.get('Z1Light') ? 300 : 0;
z2level += flow.get('Z1Light') ?  50 : 0;

// Ceiling light Z2: primary +300 lux to Z2, bleed +50 lux to Z1
z1level += flow.get('Z2Light') ?  50 : 0;
z2level += flow.get('Z2Light') ? 300 : 0;

// Blind Z1: sun * 0.5 to Z1, sun * 0.25 bleed to Z2
z1level += flow.get('Z1Blinds') ? sun * 0.50 : 0;
z2level += flow.get('Z1Blinds') ? sun * 0.25 : 0;

// Blind Z2: sun * 0.5 to Z2, sun * 0.25 bleed to Z1
z1level += flow.get('Z2Blinds') ? sun * 0.25 : 0;
z2level += flow.get('Z2Blinds') ? sun * 0.50 : 0;

// Spotlight: shared +500 lux equally to BOTH zones
var spot = flow.get('Spotlight') ? 500 : 0;
z1level += spot;
z2level += spot;

// ── Energy (per tick) ─────────────────────────────────────────────
// Ceiling lights: 1 unit/tick each
energy += flow.get('Z1Light') ? 1 : 0;
energy += flow.get('Z2Light') ? 1 : 0;
// Spotlight: 3 units/tick (high energy cost)
energy += flow.get('Spotlight') ? 3 : 0;
// Radiators: 1 unit/tick each
energy += flow.get('Z1Radiator') ? 1 : 0;
energy += flow.get('Z2Radiator') ? 1 : 0;

// ── Temperature ───────────────────────────────────────────────────
var z1temp = flow.get('Z1Temp');
var z2temp = flow.get('Z2Temp');
// Radiator on: +0.5°C/tick; off: slow drift toward 15°C at -0.05°C/tick
z1temp += flow.get('Z1Radiator') ?  0.5 : -0.05;
z2temp += flow.get('Z2Radiator') ?  0.5 : -0.05;
// Clamp to realistic range [15, 35]
z1temp = Math.min(35, Math.max(15, z1temp));
z2temp = Math.min(35, Math.max(15, z2temp));

flow.set('Z1Level', z1level);
flow.set('Z2Level', z2level);
flow.set('Z1Temp', z1temp);
flow.set('Z2Temp', z2temp);
flow.set("TotalEnergyCost", energy);

return msg;
